s-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.sfd-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.sfd-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.sfd-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(21,128,61,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.sfd-log-icon svg{stroke:#15803d}\n.sfd-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.sfd-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .sfd-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .sfd-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .sfd-log-item-label,.et_pb_section .sfd-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .sfd-log-grid{grid-template-columns:1fr}\n  .sfd-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.sfd-log-section *{transition:none !important}}\n/* === REGISTRATION CTA === */\n.sfd-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.sfd-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.sfd-reg-section>*{position:relative;z-index:2}\n.sfd-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.sfd-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.sfd-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#15803d;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(21,128,61,0.4)}\n.sfd-reg-cta:hover{background:rgb(68,153,100);transform:translateY(-2px);box-shadow:0 8px 24px rgba(21,128,61,0.3)}\n.sfd-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.sfd-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.sfd-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .sfd-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .sfd-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .sfd-reg-meta,.et_pb_section .sfd-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .sfd-reg-section h2{font-size:32px}\n  .sfd-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.sfd-reg-section *{transition:none !important}}\n/* === RELATED EVENTS === */\n.sfd-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.sfd-rel-inner{max-width:1100px;margin:0 auto}\n.sfd-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#15803d;margin-bottom:16px}\n.sfd-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.sfd-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.sfd-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.sfd-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.sfd-rel-card-border{height:4px}\n.sfd-rel-card-body{padding:28px}\n.sfd-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.sfd-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.sfd-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.sfd-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.sfd-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.sfd-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.sfd-rel-link:hover{opacity:0.8}\n\n.et_pb_section .sfd-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .sfd-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .sfd-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .sfd-rel-grid{grid-template-columns:1fr}\n  .sfd-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.sfd-rel-card{transition:none !important}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-hero-section">\n  <div class="sfd-hero-superd" aria-hidden="true"></div>\n  <a href="/news/" class="sfd-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    Back to News &amp; Events\n  </a>\n  <span class="sfd-hero-badge">Workshop</span>\n  <h1>Hands-On: Setting Up Shop Floor Data Collection with MES</h1>\n  <p class="sfd-hero-subtitle">A hands-on workshop where you configure real MES modules, connect shop floor devices, and see live OEE data flow from machine to dashboard.</p>\n\n  <div class="sfd-hero-facts">\n    \n      <div class="sfd-hero-fact">\n        <div class="sfd-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="sfd-hero-fact-value">April 24, 2026</div>\n        <div class="sfd-hero-fact-label">Thursday</div>\n      </div>\n\n      <div class="sfd-hero-fact">\n        <div class="sfd-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="sfd-hero-fact-value">09:00 – 16:00</div>\n        <div class="sfd-hero-fact-label">Full Day</div>\n      </div>\n\n      <div class="sfd-hero-fact">\n        <div class="sfd-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="sfd-hero-fact-value">Bangkok</div>\n        <div class="sfd-hero-fact-label">Thailand</div>\n      </div>\n\n      <div class="sfd-hero-fact">\n        <div class="sfd-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="sfd-hero-fact-value">25 Seats</div>\n        <div class="sfd-hero-fact-label">Limited</div>\n      </div>\n  </div>\n\n  <a href="#register" class="sfd-hero-cta">\n    Reserve Your Spot\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-prob-section">\n  <div class="sfd-prob-inner">\n    <span class="sfd-prob-label">The Challenge</span>\n    <h2 class="sfd-prob-title">Your Machines Are Running — But You Can\'t See What They\'re Doing</h2>\n  </div>\n  <div class="sfd-prob-body">\n    \n    <p>Most factories have machines running 24/7, but the data those machines generate never makes it into a system anyone can act on. Operators manually log production counts on clipboards. Downtime is recorded on paper — if it\'s recorded at all. And OEE (Overall Equipment Effectiveness) calculations happen in Excel spreadsheets, days after the fact, based on numbers everyone knows are estimates.</p>\n\n    <p>The gap between what your machines actually produce and what your system records is where profit leaks. Unplanned downtime goes undetected for hours. Quality defects get caught at end-of-line instead of at the source. And when management asks "what\'s our OEE?", the answer is a guess — not a measurement.</p>\n\n    <p>This workshop teaches you how to close that gap. You\'ll work with real MES modules and IoT devices to build a <strong>live data pipeline from the shop floor to a dashboard</strong> — and you\'ll see production data update in real-time as machines run.</p>\n    \n    <div class="sfd-prob-data-card">\n      <div class="sfd-prob-data-content">\n        <div class="sfd-prob-data-number">Paper Logs & Excel</div>\n        <div class="sfd-prob-data-arrow">&darr;</div>\n        <div class="sfd-prob-data-number sfd-prob-data-number--success">Live OEE Dashboard</div>\n        <div class="sfd-prob-data-label">From manual recording to real-time machine data in one day</div>\n      </div>\n    </div>\n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-out-section">\n  <div class="sfd-out-inner">\n    <span class="sfd-out-label">Workshop Outcomes</span>\n    <h2 class="sfd-out-title">What You\'ll Be Able to Do After This Workshop</h2>\n    <div class="sfd-out-grid">\n      \n    <div class="sfd-out-card">\n      <div class="sfd-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M12 20V10M18 20V4M6 20v-4"/></svg>\n      </div>\n      <h3>Configure MES data collection points for your specific machines</h3>\n      <p>Set up the exact data collection parameters your shop floor needs — production counts, cycle times, and machine states mapped to your equipment.</p>\n    </div>\n\n    <div class="sfd-out-card">\n      <div class="sfd-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4"/></svg>\n      </div>\n      <h3>Connect IoT sensors to capture production counts, downtime, and quality data</h3>\n      <p>Physically wire sensors to equipment interfaces and validate that machine signals are being captured correctly in the MES system.</p>\n    </div>\n\n    <div class="sfd-out-card">\n      <div class="sfd-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>\n      </div>\n      <h3>Build a live OEE dashboard that updates in real-time</h3>\n      <p>Create a working dashboard showing Availability, Performance, and Quality metrics that refresh automatically as production data flows in.</p>\n    </div>\n\n    <div class="sfd-out-card">\n      <div class="sfd-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>\n      </div>\n      <h3>Create alert rules for production anomalies</h3>\n      <p>Configure threshold-based alerts that notify the right people when downtime exceeds limits, quality rates drop, or cycle times deviate from standards.</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-agen-section">\n  <div class="sfd-agen-inner">\n    <span class="sfd-agen-label">Full-Day Agenda</span>\n    <h2 class="sfd-agen-title">Build It Yourself — Not Watch Someone Else Do It</h2>\n    <p class="sfd-agen-subtitle">Every session puts your hands on real MES modules and IoT hardware. You\'ll leave with working configurations, not just slide decks.</p>\n  </div>\n  <div class="sfd-agen-timeline">\n    \n    <div class="sfd-agen-item">\n      <div class="sfd-agen-time">09:00 – 09:30</div>\n      <div class="sfd-agen-content">\n        <h3>Registration & Setup</h3>\n        <p>Laptops required. Environment setup, software access, and a quick survey of your current shop floor data collection methods.</p>\n      </div>\n    </div>\n\n    <div class="sfd-agen-item">\n      <div class="sfd-agen-time">09:30 – 10:30</div>\n      <div class="sfd-agen-content">\n        <h3>MES Architecture — How Data Flows from Machine to Dashboard</h3>\n        <p>Understanding the data pipeline: sensor signals, edge gateways, MES collection points, and how OEE is calculated from raw machine events.</p>\n      </div>\n    </div>\n\n    <div class="sfd-agen-item sfd-agen-item--break">\n      <div class="sfd-agen-time">10:30 – 10:45</div>\n      <div class="sfd-agen-content">\n        <h3>Coffee Break</h3>\n        \n      </div>\n    </div>\n\n    <div class="sfd-agen-item">\n      <div class="sfd-agen-time">10:45 – 12:00</div>\n      <div class="sfd-agen-content">\n        <h3>Hands-On: Configuring Data Collection Points</h3>\n        <p>Working in the MES system, you\'ll define machine profiles, map signal types, and configure the data collection parameters for different equipment types.</p>\n      </div>\n    </div>\n\n    <div class="sfd-agen-item sfd-agen-item--break">\n      <div class="sfd-agen-time">12:00 – 13:00</div>\n      <div class="sfd-agen-content">\n        <h3>Networking Lunch</h3>\n        \n      </div>\n    </div>\n\n    <div class="sfd-agen-item">\n      <div class="sfd-agen-time">13:00 – 14:30</div>\n      <div class="sfd-agen-content">\n        <h3>Hands-On: Connecting Sensors & Building Your First OEE Dashboard</h3>\n        <p>Connect IoT sensors to simulated machine interfaces, validate data flow, and build a real-time OEE dashboard showing Availability, Performance, and Quality.</p>\n      </div>\n    </div>\n\n    <div class="sfd-agen-item sfd-agen-item--break">\n      <div class="sfd-agen-time">14:30 – 14:45</div>\n      <div class="sfd-agen-content">\n        <h3>Coffee Break</h3>\n        \n      </div>\n    </div>\n\n    <div class="sfd-agen-item">\n      <div class="sfd-agen-time">14:45 – 15:30</div>\n      <div class="sfd-agen-content">\n        <h3>Alert Configuration & Anomaly Detection</h3>\n        <p>Set up threshold-based alerts for downtime, quality deviations, and cycle time anomalies. Learn how to route notifications to the right people at the right time.</p>\n      </div>\n    </div>\n\n    <div class="sfd-agen-item">\n      <div class="sfd-agen-time">15:30 – 16:00</div>\n      <div class="sfd-agen-content">\n        <h3>Q&A + Implementation Planning</h3>\n        <p>Open discussion, individual architecture questions, and planning your shop floor data collection rollout back at your factory.</p>\n      </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-per-section">\n  <div class="sfd-per-inner">\n    <span class="sfd-per-label">Who This Is For</span>\n    <h2 class="sfd-per-title">Is This Workshop Right for You?</h2>\n    <div class="sfd-per-grid">\n      \n    <div class="sfd-per-card">\n      <div class="sfd-per-accent"></div>\n      <div class="sfd-per-body">\n        <div class="sfd-per-role">IT / System Administrator</div>\n        <span class="sfd-per-size">Evaluating MES for the Factory</span>\n        <p class="sfd-per-desc">You\'re the person management will ask to evaluate and implement MES. You need to understand the technical architecture — network requirements, sensor protocols, data storage — before you can recommend it.</p>\n        <p class="sfd-per-quote">"I need to understand the technical architecture before recommending MES to management."</p>\n      </div>\n    </div>\n\n    <div class="sfd-per-card">\n      <div class="sfd-per-accent"></div>\n      <div class="sfd-per-body">\n        <div class="sfd-per-role">Production Engineer</div>\n        <span class="sfd-per-size">Any Size Manufacturing</span>\n        <p class="sfd-per-desc">You run the production line and you know the data your operators record on paper is incomplete and late. You want machines to report their own status — automatically, accurately, in real-time.</p>\n        <p class="sfd-per-quote">"I want to capture machine data automatically instead of relying on operators to fill in forms."</p>\n      </div>\n    </div>\n\n    <div class="sfd-per-card">\n      <div class="sfd-per-accent"></div>\n      <div class="sfd-per-body">\n        <div class="sfd-per-role">Continuous Improvement Manager</div>\n        <span class="sfd-per-size">Lean / Six Sigma Practitioner</span>\n        <p class="sfd-per-desc">Your improvement projects depend on accurate data, but the OEE numbers you\'ve been working with are estimates based on operator logs. You need real measurements to drive real improvements.</p>\n        <p class="sfd-per-quote">"I need real OEE numbers, not the estimates we\'ve been using."</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-prf-section">\n  <div class="sfd-prf-inner">\n    <span class="sfd-prf-label">Why DigiWin Events</span>\n    <h2 class="sfd-prf-title">Learn from the Team That\'s Done This 100+ Times</h2>\n    <div class="sfd-prf-stats-bar">\n      \n    <div class="sfd-prf-stat">\n      <div class="sfd-prf-stat-value">100+</div>\n      <div class="sfd-prf-stat-label">Thai Implementations</div>\n    </div>\n\n    <div class="sfd-prf-stat">\n      <div class="sfd-prf-stat-value">44</div>\n      <div class="sfd-prf-stat-label">Years Manufacturing ERP</div>\n    </div>\n\n    <div class="sfd-prf-stat">\n      <div class="sfd-prf-stat-value">95%</div>\n      <div class="sfd-prf-stat-label">Contract Renewal Rate</div>\n    </div>\n\n    <div class="sfd-prf-stat">\n      <div class="sfd-prf-stat-value">50+</div>\n      <div class="sfd-prf-stat-label">Thai Team Members</div>\n    </div>\n    </div>\n    <p class="sfd-prf-text">DigiWin has connected thousands of machines across Asia to MES systems over the past 44 years. This workshop distills that experience into a single day — the same configuration approach our implementation engineers use with every new factory deployment.</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="sfd-log-section">\n  <div class="sfd-log-inner">\n    <span class="sfd-log-label">Practical Details</span>\n    <h2 class="sfd-log-title">Everything You Need to Know</h2>\n    <div class="sfd-log-grid">\n      \n    <div class="sfd-log-item">\n      <div class="sfd-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n      </div>\n      <div>\n        <div class="sfd-log-item-label">Date</div>\n        <div class="sfd-log-item-value">Thursday, April 24, 2026</div>\n      </div>\n    </div>\n\n    <div class="sfd-log-item">\n      <div class="sfd-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n      </div>\n      <div>\n        <div class="sfd-log-item-label">Time</div>\n        <div class="sfd-log-item-value">09:00 – 16:00 (registration opens 08:30)</div>\n      </div>\n    </div>\n\n    <div class="sfd-log-item">\n      <div class="sfd-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n      </div>\n      <div>\n        <div class="sfd-log-item-label">Location</div>\n        <div class="sfd-log-item-value">Bangkok, Thailand (venue details sent after registration)</div>\n      </div>\n    </div>\n\n    <div class="sfd-log-item">\n      <div class="sfd-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n      </div>\n      <div>\n        <div class="sfd-log-item-label"