== */\n.sfd-out-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.sfd-out-inner{max-width:1100px;margin:0 auto}\n.sfd-out-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#15803d;margin-bottom:16px}\n.sfd-out-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.sfd-out-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.sfd-out-card{background:#fff;border-radius:16px;padding:32px;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.sfd-out-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.sfd-out-icon{width:48px;height:48px;border-radius:50%;background:rgba(21,128,61,0.1);display:flex;align-items:center;justify-content:center;margin-bottom:16px}\n.sfd-out-icon svg{stroke:#15803d}\n.sfd-out-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px;padding:0}\n.sfd-out-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n\n.et_pb_section .sfd-out-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .sfd-out-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .sfd-out-card h3{-webkit-font-smoothing:auto !important;margin:0 0 8px !important;padding:0 !important}\n.et_pb_section .sfd-out-card p{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .sfd-out-grid{grid-template-columns:1fr}\n  .sfd-out-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.sfd-out-card{transition:none !important}}\n/* === AGENDA === */\n.sfd-agen-section{background:#fff;pad